function worked_http_ts_tls_trust_2(scheme: string, hostnameMatches: boolean, chainTrusted: boolean): { accepted: boolean; reason: string } {
  if (scheme.toLowerCase() !== "https") return { accepted: false, reason: "downgrade" };
  if (!hostnameMatches) return { accepted: false, reason: "hostname" };
  if (!chainTrusted) return { accepted: false, reason: "trust chain" };
  return { accepted: true, reason: "authenticated transport" };
}

